import { useEffect, useRef, useState } from "react";
import Card from "./Card";

// ─── Helpers ──────────────────────────────────────────────────────────────────
export const lerp = (a, b, t) => a + (b - a) * t;
export const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));
export const ease = (t) =>
  t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;

// ─── Horizontal oval radii ────────────────────────────────────────────────────
export const RX = 38; // vw  (wide)
export const RY = 22; // vh  (flat/short)

// ─── Card definitions ─────────────────────────────────────────────────────────
export const CARDS = [
  { id: 1,  label: "AI Model",  emoji: "🧠", angle: 180, rotate: -14, accent: "#7c3aed", z: 6  },
  { id: 2,  label: "Face ID",   emoji: "📷", angle: 150, rotate:  9,  accent: "#6d28d9", z: 7  },
  { id: 3,  label: "KYC",       emoji: "🪪", angle: 120, rotate: -6,  accent: "#f59e0b", z: 8  },
  { id: 4,  label: "Verified",  emoji: "✅", angle:  90, rotate:  4,  accent: "#10b981", z: 9  },
  { id: 5,  label: "Mobile",    emoji: "📱", angle:  60, rotate: -9,  accent: "#6d28d9", z: 8  },
  { id: 6,  label: "Email",     emoji: "📧", angle:  30, rotate:  16, accent: "#b45309", z: 7  },
  { id: 7,  label: "Docs",      emoji: "📄", angle:   0, rotate: -7,  accent: "#2563eb", z: 6  },
  { id: 8,  label: "Bank",      emoji: "🏦", angle: 330, rotate:  11, accent: "#15803d", z: 7  },
  { id: 9,  label: "Score",     emoji: "📊", angle: 300, rotate: -5,  accent: "#d97706", z: 8  },
  { id: 10, label: "Scan Doc",  emoji: "🔍", angle: 270, rotate:  6,  accent: "#7c3aed", z: 9  },
  { id: 11, label: "Map",       emoji: "🗺️", angle: 240, rotate: -11, accent: "#0891b2", z: 8  },
  { id: 12, label: "Address",   emoji: "📍", angle: 210, rotate:  9,  accent: "#dc2626", z: 7  },
];

// ─── Component ────────────────────────────────────────────────────────────────
export default function ScrollHero() {
  const [progress, setProgress] = useState(0);
  const sectionRef = useRef(null);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const p = clamp(
        -el.getBoundingClientRect().top / (el.offsetHeight * 0.62),
        0,
        1
      );
      setProgress(p);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // ── Derived animation values ──────────────────────────────────────────────
  const headingScale = lerp(0.48, 1, ease(clamp(progress / 0.75, 0, 1)));

  const colorT = ease(clamp((progress - 0.3) / 0.5, 0, 1));
  const headingColor = `rgb(${Math.round(lerp(255, 170, colorT))}, 255, ${Math.round(
    lerp(255, 0, colorT)
  )})`;

  const subP = ease(clamp((progress - 0.62) / 0.28, 0, 1));
  const btnP = ease(clamp((progress - 0.74) / 0.26, 0, 1));

  return (
    <>
      {/* 300 vh scroll driver */}
      <div ref={sectionRef} style={{ height: "300vh", position: "relative" }}>
        <div
          style={{
            position: "sticky",
            top: 0,
            height: "100vh",
            overflow: "hidden",
            background: "#5b21b6",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          {/* Grid background */}
          <div
            style={{
              position: "absolute",
              inset: 0,
              backgroundImage:
                "linear-gradient(rgba(255,255,255,0.06) 1px, transparent 1px)," +
                "linear-gradient(90deg, rgba(255,255,255,0.06) 1px, transparent 1px)",
              backgroundSize: "50px 50px",
            }}
          />

          {/* Cards on the horizontal oval */}
          {CARDS.map((card) => (
            <Card key={card.id} card={card} progress={progress} />
          ))}

          {/* Central hero text */}
          <div
            style={{
              position: "relative",
              zIndex: 20,
              textAlign: "center",
              transform: `scale(${headingScale})`,
              willChange: "transform",
              padding: "0 20px",
              maxWidth: 960,
            }}
          >
            {/* Main heading */}
            <h1
              style={{
                fontFamily:
                  "'Impact', 'Arial Black', 'Haettenschweiler', sans-serif",
                fontSize: "clamp(56px, 9.5vw, 148px)",
                fontWeight: 900,
                color: headingColor,
                margin: 0,
                lineHeight: 0.95,
                textTransform: "uppercase",
                willChange: "color",
              }}
            >
              Going Beyond
            </h1>

            {/* Sub-heading */}
            <h2
              style={{
                fontFamily: "'Georgia', serif",
                fontSize: "clamp(18px, 2.5vw, 36px)",
                fontWeight: 700,
                color: "white",
                margin: "16px 0 10px",
                opacity: subP,
                transform: `translateY(${lerp(22, 0, subP)}px)`,
                transition: "none",
              }}
            >
              Financial Score
            </h2>

            {/* Body copy */}
            <p
              style={{
                color: "rgba(255,255,255,0.85)",
                fontSize: "clamp(13px, 1.05vw, 17px)",
                opacity: subP,
                transform: `translateY(${lerp(16, 0, subP)}px)`,
                maxWidth: 500,
                margin: "0 auto 30px",
                lineHeight: 1.7,
                transition: "none",
              }}
            >
              The easiest way to verify emails, identities, and detect forged
              documents: all in real time.
            </p>

            {/* CTA Buttons */}
            <div
              style={{
                display: "flex",
                gap: 14,
                justifyContent: "center",
                flexWrap: "wrap",
                opacity: btnP,
                transform: `translateY(${lerp(26, 0, btnP)}px)`,
                transition: "none",
              }}
            >
              <button
                style={{
                  background: "#aaff00",
                  color: "#111",
                  border: "none",
                  padding: "14px 40px",
                  borderRadius: 999,
                  fontSize: 16,
                  fontWeight: 800,
                  cursor: "pointer",
                  boxShadow: "0 4px 24px rgba(170,255,0,0.45)",
                  fontFamily: "inherit",
                  letterSpacing: 0.3,
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.transform = "scale(1.04)")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.transform = "scale(1)")
                }
              >
                Try For Free
              </button>
              <button
                style={{
                  background: "rgba(255,255,255,0.10)",
                  color: "white",
                  border: "2px solid rgba(255,255,255,0.38)",
                  padding: "14px 40px",
                  borderRadius: 999,
                  fontSize: 16,
                  fontWeight: 700,
                  cursor: "pointer",
                  backdropFilter: "blur(12px)",
                  fontFamily: "inherit",
                  letterSpacing: 0.3,
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.background = "rgba(255,255,255,0.20)")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.background = "rgba(255,255,255,0.10)")
                }
              >
                Explore the Suite
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* ── Section below hero ── */}
      <div
        style={{
          padding: "100px 40px",
          textAlign: "center",
          background: "#f5f3ff",
        }}
      >
        <h3
          style={{
            fontSize: 28,
            color: "#5b21b6",
            fontFamily: "'Georgia', serif",
            marginBottom: 14,
          }}
        >
          Beyond Financial Score
        </h3>
        <p
          style={{
            color: "#64748b",
            maxWidth: 520,
            margin: "0 auto",
            lineHeight: 1.75,
            fontSize: 16,
            fontFamily: "system-ui, sans-serif",
          }}
        >
          Real-time identity verification, document fraud detection, and credit
          intelligence — all in one platform.
        </p>
        <button
          style={{
            marginTop: 32,
            background: "#7c3aed",
            color: "white",
            border: "none",
            padding: "14px 36px",
            borderRadius: 999,
            fontSize: 15,
            fontWeight: 700,
            cursor: "pointer",
            fontFamily: "system-ui, sans-serif",
          }}
        >
          ↑ Scroll back up to replay
        </button>
      </div>
    </>
  );
}
